mapper.select:
select index_id, park_key, car_no, order_no, car_type_no, out_time, out_gate_name, out_operator_name, lock_car, out_img_path, free_reason, total_amount, enter_time,create_time,update_time
from get_out_car where
park_key = #{parkKey}
and car_no = #{carNo}
and order_no = #{orderNo}
and car_type_no = #{carTypeNo}
